import { useEffect, useMemo, useState } from 'react';
import AuthForm from './components/AuthForm';
import ProductDetails from './components/ProductDetails';
import ProductList from './components/ProductList';
import ProductModal from './components/ProductModal';
import {
  clearTokens,
  deleteProduct,
  getCurrentUser,
  getProductById,
  getProducts,
  hasStoredTokens,
  loginUser,
  registerUser,
  setUnauthorizedHandler
} from './api/api';
import './styles/main.scss';

function App() {
  const [products, setProducts] = useState([]);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('все');
  const [authMode, setAuthMode] = useState('login');
  const [user, setUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [formLoading, setFormLoading] = useState(false);
  const [detailId, setDetailId] = useState('');
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [detailLoading, setDetailLoading] = useState(false);

  const loadProducts = async () => {
    try {
      const data = await getProducts();
      setProducts(data);
    } catch (error) {
      alert(error.message || 'Не удалось загрузить товары');
    }
  };

  const handleLogout = () => {
    clearTokens();
    setUser(null);
    setProducts([]);
    setSelectedProduct(null);
    setDetailId('');
    setAuthMode('login');
  };

  useEffect(() => {
    setUnauthorizedHandler(handleLogout);
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      if (!hasStoredTokens()) {
        setAuthLoading(false);
        return;
      }

      try {
        const currentUser = await getCurrentUser();
        setUser(currentUser);
      } catch (error) {
        clearTokens();
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();
  }, []);

  useEffect(() => {
    if (user) {
      loadProducts();
    }
  }, [user]);

  const filteredProducts = useMemo(() => {
    return products.filter((product) => {
      const matchesSearch = searchTerm
        ? product.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
          product.description.toLowerCase().includes(searchTerm.toLowerCase())
        : true;

      const matchesCategory = selectedCategory === 'все' || product.category === selectedCategory;

      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, selectedCategory]);

  const categories = useMemo(() => {
    return ['все', ...new Set(products.map((product) => product.category))];
  }, [products]);

  const openModal = (product = null) => {
    setEditingProduct(product);
    setModalOpen(true);
  };

  const closeModal = () => {
    setModalOpen(false);
    setEditingProduct(null);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Удалить позицию из меню?')) {
      return;
    }

    try {
      await deleteProduct(id);
      setProducts((prev) => prev.filter((product) => product.id !== id));
      if (selectedProduct?.id === id) {
        setSelectedProduct(null);
      }
    } catch (error) {
      alert(error.message || 'Не удалось удалить товар');
    }
  };

  const handleAuthSubmit = async (payload) => {
    setFormLoading(true);

    try {
      if (authMode === 'register') {
        await registerUser(payload);
      }

      const currentUser = await loginUser({
        email: payload.email,
        password: payload.password
      });

      setUser(currentUser);
    } catch (error) {
      alert(error.message || 'Ошибка авторизации');
    } finally {
      setFormLoading(false);
    }
  };

  const handleLoadProduct = async (id) => {
    if (!id.trim()) {
      alert('Введите id товара');
      return;
    }

    setDetailLoading(true);

    try {
      const product = await getProductById(id.trim());
      setSelectedProduct(product);
      setDetailId(product.id);
    } catch (error) {
      alert(error.message || 'Не удалось загрузить товар');
    } finally {
      setDetailLoading(false);
    }
  };

  if (authLoading) {
    return <div className="app-status">Проверка сессии...</div>;
  }

  if (!user) {
    return (
      <div className="auth-page">
        <div className="auth-card">
          <h1>MIX Coffee</h1>
          <p>Авторизуйтесь, чтобы управлять товарами и работать с API.</p>

          <div className="auth-tabs">
            <button
              className={`category-btn ${authMode === 'login' ? 'active' : ''}`}
              onClick={() => setAuthMode('login')}
            >
              Вход
            </button>
            <button
              className={`category-btn ${authMode === 'register' ? 'active' : ''}`}
              onClick={() => setAuthMode('register')}
            >
              Регистрация
            </button>
          </div>

          <AuthForm mode={authMode} onSubmit={handleAuthSubmit} loading={formLoading} />
        </div>
      </div>
    );
  }

  return (
    <div className="app">
      <header className="app-header">
        <div>
          <h1>MIX Coffee</h1>
          <p>
            Пользователь: {user.first_name} {user.last_name} ({user.email})
          </p>
        </div>
        <button className="btn delete" onClick={handleLogout}>
          Выйти
        </button>
      </header>

      <div className="toolbar">
        <button className="btn btn-add" onClick={() => openModal()}>
          + Добавить товар
        </button>
        <button className="btn view" onClick={loadProducts}>
          Обновить список
        </button>
      </div>

      <div className="controls">
        <div className="search-container">
          <input
            type="text"
            className="search-input"
            placeholder="Поиск по названию или описанию..."
            value={searchTerm}
            onChange={(event) => setSearchTerm(event.target.value)}
          />
        </div>

        <div className="categories">
          {categories.map((category) => (
            <button
              key={category}
              className={`category-btn ${selectedCategory === category ? 'active' : ''}`}
              onClick={() => setSelectedCategory(category)}
            >
              {category}
            </button>
          ))}
        </div>

        <div className="product-id-panel">
          <input
            type="text"
            placeholder="Введите id товара"
            value={detailId}
            onChange={(event) => setDetailId(event.target.value)}
          />
          <button className="btn view" onClick={() => handleLoadProduct(detailId)} disabled={detailLoading}>
            {detailLoading ? 'Загрузка...' : 'Получить по id'}
          </button>
        </div>
      </div>

      <div className="content-layout">
        <ProductList
          products={filteredProducts}
          onEdit={openModal}
          onDelete={handleDelete}
          onView={handleLoadProduct}
        />

        <ProductDetails product={selectedProduct} />
      </div>

      <ProductModal
        open={modalOpen}
        product={editingProduct}
        onClose={closeModal}
        onSave={loadProducts}
      />
    </div>
  );
}

export default App;
